export const getPlay = (slug: string): Play | undefined => {
  if (!slug || typeof slug !== "string") return undefined;
  try {
    return plays.find((p) => p?.slug === slug);
  } catch (err) {
    console.error("[getPlay] lookup failed", err);
    return undefined;
  }
};

export const getCharacter = (
  playSlug: string,
  charSlug: string
): { play: Play; character: Character } | undefined => {
  if (!playSlug || !charSlug) return undefined;
  try {
    const play = getPlay(playSlug);
    if (!play) return undefined;
    const character = play.characters?.find((c) => c?.slug === charSlug);
    if (!character) return undefined;
    return { play, character };
  } catch (err) {
    console.error("[getCharacter] lookup failed", err);
    return undefined;
  }
};
